pub enum Action {
    View,
    Edit,
    Delete,
    Escalate,
}

pub fn decide(role: Role, route: Route, action: Action, suspended: bool) -> &'static str {
    match route {
        Route::Home => "allow",
        Route::Billing => match action {
            Action::View => match role {
                Role::Admin | Role::Staff => "allow",
                _ => "deny",
            },
            Action::Edit => match role {
