pub fn parse_records(input: &str) -> Result<Vec<Record>, String> {
    let mut out = Vec::new();
    for (line_no, raw) in input.lines().enumerate() {
        let line = raw.trim();
        if line.is_empty() {
            continue;
        }

        let mut id = 0u32;
        let mut kind = String::new();
        let mut value = 0i32;
        let mut tags = Vec::new();

