                "value" => {
                    value = val.parse().unwrap_or(0);
                }
                "tags" => {
                    if !val.is_empty() {
                        tags = val.split(',').map(|s| s.trim().to_string()).collect();
                    }
                }
                _ => {}
            }
        }

        if id == 0 || kind.is_empty() {
            continue;
        }

        out.push(Record { id, kind, value, tags });
        let _ = line_no;
    }
    Ok(out)
