    "src/lib.rs": "use std::collections::{BTreeMap, BTreeSet};

#[derive(Clone, Debug)]
pub struct SaleRecord<'a> {
    pub week: &'a str,
    pub region: &'a str,
    pub salesperson: &'a str,
    pub customer_id: &'a str,
    pub units: u32,
    pub amount_cents: i64,
    pub refunded: bool,
}

fn is_valid(rec: &SaleRecord<'_>) -> bool {
    !rec.week.is_empty() && !rec.region.is_empty() && !rec.salesperson.is_empty() && !rec.customer_id.is_empty()
}

pub fn weekly_region_report(records: &[SaleRecord<'_>]) -> String {
    let mut groups: BTreeMap<&str, (i64, u32, usize, BTreeSet<&str>)> = BTreeMap::new();

    for rec in records {
        if !is_valid(rec) {
            continue;
        }
        let entry = groups.entry(rec.region).or_insert((0, 0, 0, BTreeSet::new()));
        entry.0 += rec.amount_cents;
        entry.1 += rec.units;
        entry.2 += 1;
        entry.3.insert(rec.customer_id);
    }

    let mut rows: Vec<_> = groups
        .into_iter()
        .map(|(region, (amount, units, orders, customers))| (region, amount, units, orders, customers.len()))
        .collect();

    rows.sort_by(|a, b| a.0.cmp(b.0));

    let total_amount: i64 = rows.iter().map(|r| r.1).sum();
    let total_units: u32 = rows.iter().map(|r| r.2).sum();
    let total_orders: usize = rows.iter().map(|r| r.3).sum();

    let mut out = vec![format!("TOTAL amount_cents={} units={} orders={}", total_amount, total_units, total_orders)];
    for (region, amount, units, orders, customers) in rows {
        out.push(format!(
            "{} amount_cents={} units={} orders={} unique_customers={}",
            region, amount, units, orders, customers
        ));
    }
    out.join("\n")
}

