pub enum Role {
    Guest,
    Member,
    Moderator,
    Admin,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Route {
    Home,
    Profile,
    Billing,
    AdminPanel,
    Audit,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Action {
    View,
    Edit,
    Delete,
    Export,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Decision {
    Allow,
    RequireLogin,
    Deny,
    Escalate,
}

pub fn decide(role: Role, route: Route, action: Action, suspended: bool) -> Decision {
    match route {
        Route::Home => Decision::Allow,
        Route::Profile => match action {
            Action::View => Decision::Allow,
            Action::Edit => {
                if role == Role::Guest {
                    Decision::RequireLogin
                } else {
                    Decision::Allow
                }
            }
            _ => Decision::Deny,
        },
        Route::Billing => match action {
            Action::View | Action::Export => {
                if role == Role::Guest {
                    Decision::RequireLogin
                } else {
                    Decision::Allow
                }
            }
            _ => Decision::Deny,
        },
        Route::AdminPanel => match action {
            Action::View => {
                if role == Role::Admin {
                    Decision::Allow
                } else {
                    Decision::Deny
                }
            }
            Action::Edit | Action::Delete => {
                if role == Role::Admin || role == Role::Moderator {
                    Decision::Allow
                } else {
                    Decision::Deny
                }
            }
            Action::Export => Decision::Allow,
        },
        Route::Audit => match action {
            Action::View => {
                if role == Role::Admin || role == Role::Moderator {
                    Decision::Allow
                } else {
                    Decision::Deny
                }
            }
            Action::Export => {
                if role == Role::Admin {
                    Decision::Allow
                } else {
                    Decision::Deny
                }
            }
            _ => Decision::Deny,
        },
    }
}

