fn parse_file(input: &str) -> Config {
    let mut cfg = Config::empty();
    for line in input.lines() {
        let line = line.trim();
        if line.is_empty() || line.starts_with('#') {
            continue;
        }
        let Some((k, v)) = line.split_once('=') else { continue };
        let key = k.trim();
        let val = v.trim();
        match key {
            "host" => {
                if !val.is_empty() {
                    cfg.host = Some(val.to_string());
                }
            }
            "port" => {
                if let Ok(p) = val.parse::<u16>() {
                    cfg.port = Some(p);
                }
            }
            "color" => match val {
                "true" => cfg.color = Some(true),
                "false" => cfg.color = Some(false),
                _ => {}
            },
            "mode" => {
                if !val.is_empty() {
                    cfg.mode = Some(val.to_string());
                }
            }
            _ => {}
        }
    }
    cfg
}

fn parse_env(env: &HashMap<&str, &str>) -> Config {
    let mut cfg = Config::empty();
    if let Some(v) = env.get("APP_HOST") {
        if !v.is_empty() {
            cfg.host = Some((*v).to_string());
