}

fn parse_cli(args: &[&str]) -> Config {
    let mut cfg = Config::empty();
    let mut i = 0;
    while i < args.len() {
        match args[i] {
            "--host" if i + 1 < args.len() => {
                let v = args[i + 1];
                if !v.is_empty() {
                    cfg.host = Some(v.to_string());
