version = "0.1.0"
edition = "2021"

[dependencies]
",
    "src/lib.rs": "use std::collections::HashMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Entry {
    pub player_id: &'static str,
    pub display_name: &'static str,
    pub score: i32,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct RankedPlayer {
    pub rank: usize,
    pub player_id: String,
    pub display_name: String,
    pub best_score: i32,
}

pub fn build_leaderboard(entries: &[Entry]) -> Vec<RankedPlayer> {
    let mut merged: HashMap<&str, (i32, &str, usize)> = HashMap::new();

    for (idx, entry) in entries.iter().enumerate() {
        merged
            .entry(entry.player_id)
            .and_modify(|slot| {
                if entry.score >= slot.0 {
                    *slot = (entry.score, entry.display_name, idx);
                }
            })
            .or_insert((entry.score, entry.display_name, idx));
    }

    let mut players: Vec<RankedPlayer> = merged
        .into_iter()
        .map(|(player_id, (best_score, display_name, _first_seen))| RankedPlayer {
            rank: 0,
            player_id: player_id.to_string(),
            display_name: display_name.to_string(),
            best_score,
        })
        .collect();

    players.sort_by(|a, b| {
        b.best_score
            .cmp(&a.best_score)
            .then_with(|| a.display_name.cmp(&b.display_name))
    });

    for (idx, player) in players.iter_mut().enumerate() {
        player.rank = idx + 1;
    }

    players
}

