#[derive(Debug, Clone)]
pub struct SaleRecord<'a> {
    pub week: u32,
    pub region: &'a str,
    pub rep_id: &'a str,
    pub order_id: &'a str,
    pub amount_cents: i64,
    pub valid: bool,
}

#[derive(Debug, PartialEq, Eq)]
pub struct RegionSummary {
    pub region: String,
    pub total_cents: i64,
    pub unique_reps: usize,
    pub order_count: usize,
}

pub fn weekly_region_summary(records: &[SaleRecord], week: u32) -> Vec<RegionSummary> {
    let mut by_region: BTreeMap<String, (i64, usize, usize)> = BTreeMap::new();

    for r in records {
        if r.week != week {
            continue;
        }

        let entry = by_region.entry(r.region.to_string()).or_insert((0, 0, 0));
        entry.0 += r.amount_cents;
        entry.1 += 1;
        entry.2 += 1;
    }

    by_region
        .into_iter()
        .map(|(region, (total_cents, unique_reps, order_count))| RegionSummary {
            region,
            total_cents,
            unique_reps,
            order_count,
        })
        .collect()
}

pub fn render_report(rows: &[RegionSummary]) -> String {
    rows.iter()
        .map(|r| format!("{}|{}|{}|{}", r.region, r.total_cents, r.unique_reps, r.order_count))
        .collect::<Vec<_>>()
        .join("\n")
}

