pub enum Role {
    Guest,
    Member,
    Moderator,
    Admin,
    Service,
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum Route {
    Home,
    Profile,
    AdminPanel,
    Billing,
    Audit,
    Support,
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum Action {
    View,
    Edit,
    Delete,
    Approve,
}

pub fn policy_decision(role: Role, route: Route, action: Action, suspended: bool) -> &'static str {
    if suspended {
        return "deny";
    }

    match route {
        Route::Home => "allow",
        Route::Profile => match action {
            Action::View => "allow",
            _ => "deny",
        },
        Route::AdminPanel => match role {
            Role::Admin => "allow",
            _ => "deny",
        },
        Route::Billing => match role {
            Role::Admin => "allow",
            Role::Member => "allow",
            _ => "deny",
        },
        Route::Audit => match role {
            Role::Admin => "allow",
            _ => "deny",
        },
        Route::Support => match role {
            Role::Moderator => "allow",
            Role::Admin => "allow",
            _ => "deny",
        },
    }
}

