    fn guests_have_limited_access() {
        assert_eq!(policy_decision(Role::Guest, Route::Home, Action::View, false), "allow");
        assert_eq!(policy_decision(Role::Guest, Route::Profile, Action::View, false), "allow");
        assert_eq!(policy_decision(Role::Guest, Route::Profile, Action::Edit, false), "deny");
        assert_eq!(policy_decision(Role::Guest, Route::Billing, Action::View, false), "deny");
