        retries: 3,
        debug: true,
        timeout: 30,
        endpoint: "https://default.local".to_string(),
        token: "default-token".to_string(),
    }
}

fn parse_pairs(input: &str) -> PartialConfig {
    let mut cfg = PartialConfig::default();
    for raw in input.lines() {
        let line = raw.trim();
        if line.is_empty() || line.starts_with('#') {
            continue;
        }
        if let Some((k, v)) = line.split_once('=') {
            let key = k.trim();
            let val = v.trim();
            match key {
                "profile" => {
                    if !val.is_empty() {
                        cfg.profile = Some(val.to_string());
                    }
                }
                "retries" => {
                    if let Ok(n) = val.parse::<u32>() {
                        cfg.retries = Some(n);
                    }
                }
                "debug" => {
                    if val == "true" {
                        cfg.debug = Some(true);
                    }
                }
                "timeout" => {
                    if let Ok(n) = val.parse::<u32>() {
                        if n > 0 {
                            cfg.timeout = Some(n);
                        }
                    }
                }
                "endpoint" => {
                    if !val.is_empty() {
                        cfg.endpoint = Some(val.to_string());
                    }
                }
                "token" => {
                    if !val.is_empty() {
                        cfg.token = Some(val.to_string());
                    }
                }
                _ => {}
            }
        }
    }
    cfg
}

fn merge(base: &mut Config, layer: PartialConfig) {
    if let Some(v) = layer.profile {
        base.profile = v;
    }
    if let Some(v) = layer.retries {
        if v > 0 {
            base.retries = v;
        }
    }
    if let Some(v) = layer.debug {
        if v {
            base.debug = v;
        }
    }
    if let Some(v) = layer.timeout {
        if v > 0 {
            base.timeout = v;
        }
    }
    if let Some(v) = layer.endpoint {
        if !v.is_empty() {
            base.endpoint = v;
        }
    }
    if let Some(v) = layer.token {
        if !v.is_empty() {
            base.token = v;
        }
    }
}

fn main() {
    let file_cfg = parse_pairs(
        "profile=file\nretries=2\ndebug=true\ntimeout=15\nendpoint=https://file.local\ntoken=file-token\n",
    );
    let env_cfg = parse_pairs(
        "profile=env\nretries=0\ndebug=false\ntimeout=0\nendpoint=\ntoken=env-token\n",
    );
    let cli_cfg = parse_pairs(
        "profile=\nendpoint=\ntoken=\n",
    );

    let mut effective = defaults();
    merge(&mut effective, cli_cfg);
    merge(&mut effective, env_cfg);
    merge(&mut effective, file_cfg);

    println!("profile={}", effective.profile);
    println!("retries={}", effective.retries);
    println!("debug={}", effective.debug);
    println!("timeout={}", effective.timeout);
    println!("endpoint={}", effective.endpoint);
    print!("token={}", effective.token);
}
