    "src/lib.rs": "use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Entry {
    pub name: String,
    pub score: u32,
    pub penalties: u32,
    pub solved: u32,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Ranked {
    pub rank: usize,
    pub name: String,
    pub score: u32,
    pub penalties: u32,
    pub solved: u32,
}

pub fn rank_entries(entries: &[Entry]) -> Vec<Ranked> {
    let mut merged: BTreeMap<String, Entry> = BTreeMap::new();
    for e in entries {
        merged
            .entry(e.name.clone())
            .and_modify(|cur| {
                cur.score += e.score;
                cur.penalties += e.penalties;
                cur.solved += e.solved;
            })
            .or_insert_with(|| e.clone());
    }

    let mut items: Vec<Entry> = merged.into_values().collect();
    items.sort_by(|a, b| b.score.cmp(&a.score).then_with(|| a.name.cmp(&b.name)));

    let mut out = Vec::new();
    let mut last_score = None;
    let mut rank = 0;
    for (idx, e) in items.into_iter().enumerate() {
        if last_score != Some(e.score) {
            rank = idx + 1;
            last_score = Some(e.score);
        }
        out.push(Ranked {
            rank,
            name: e.name,
            score: e.score,
            penalties: e.penalties,
            solved: e.solved,
        });
    }
    out
}

