pub enum Status {
    Ready,
    Snoozed,
    Disabled,
}

#[derive(Clone, Debug)]
pub struct Candidate {
    pub id: &'static str,
    pub status: Status,
    pub score: i32,
    pub seen_at: Option<u32>,
    pub hidden: bool,
}

pub fn pick_candidates(items: &[Candidate], now_minute: u32) -> Vec<&'static str> {
    let mut out: Vec<_> = items
        .iter()
        .filter(|c| c.status == Status::Ready)
        .filter(|c| !c.hidden)
        .filter(|c| c.score > 0)
        .filter_map(|c| {
            let age = now_minute.saturating_sub(c.seen_at.unwrap_or(now_minute));
            if age > 30 {
                Some((c.id, c.score, age))
            } else {
                None
            }
        })
        .collect();

    out.sort_by(|a, b| b.1.cmp(&a.1).then_with(|| b.2.cmp(&a.2)).then_with(|| a.0.cmp(b.0)));
    out.into_iter().map(|(id, _, _)| id).collect()
}

