pub struct Record {
    pub id: u32,
    pub kind: String,
    pub value: i32,
    pub tags: Vec<String>,
}

pub fn parse_records(input: &str) -> Result<Vec<Record>, String> {
    let mut out = Vec::new();
    for (idx, raw) in input.lines().enumerate() {
        let line = raw.trim();
        if line.is_empty() {
            continue;
        }

        let mut id: Option<u32> = None;
        let mut kind: Option<String> = None;
        let mut value: Option<i32> = None;
        let mut tags: Vec<String> = Vec::new();

        for part in line.split('|') {
            let mut kv = part.splitn(2, '=');
            let key = kv.next().unwrap_or("").trim();
            let val = kv.next().unwrap_or("").trim();

            match key {
                "id" => id = val.parse::<u32>().ok(),
                "kind" => kind = Some(val.to_string()),
                "value" => value = val.parse::<i32>().ok(),
                "tags" => {
                    if !val.is_empty() {
                        tags = val.split(',').map(|s| s.trim().to_string()).collect();
                    }
                }
                _ => {}
            }
        }

        let id = id.ok_or_else(|| format!("line {}: missing id", idx + 1))?;
        let kind = kind.ok_or_else(|| format!("line {}: missing kind", idx + 1))?;
        let value = value.unwrap_or(0);

        out.push(Record { id, kind, value, tags });
    }
    Ok(out)
}

