    "src/lib.rs": "use std::collections::BTreeMap;

#[derive(Debug, Clone)]
pub struct SaleRecord<'a> {
    pub week: &'a str,
    pub channel: &'a str,
    pub customer_id: &'a str,
    pub order_id: &'a str,
    pub amount_cents: i64,
    pub completed: bool,
    pub refunded: bool,
}

#[derive(Debug, PartialEq, Eq)]
pub struct ChannelSummary {
    pub week: String,
    pub channel: String,
    pub orders: usize,
    pub unique_customers: usize,
    pub gross_cents: i64,
}

pub fn weekly_channel_report(records: &[SaleRecord<'_>]) -> Vec<ChannelSummary> {
    let mut grouped: BTreeMap<(String, String), (usize, usize, i64)> = BTreeMap::new();

    for r in records {
        if !r.completed {
            continue;
        }

        let key = (r.week.to_string(), r.channel.to_string());
        let entry = grouped.entry(key).or_insert((0, 0, 0));
        entry.0 += 1;
        entry.1 += 1;
        entry.2 += r.amount_cents;
    }

