#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum Route {
    Home,
    Profile,
    AdminPanel,
    ModQueue,
    Billing,
    Support,
    Api,
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum Action {
    View,
    Edit,
    Delete,
    Refund,
    BanUser,
}

pub fn is_allowed(role: Role, route: Route, action: Action) -> bool {
    match route {
        Route::Home => true,
        Route::Profile => matches!(action, Action::View | Action::Edit),
        Route::AdminPanel => matches!(role, Role::Admin),
        Route::ModQueue => matches!(role, Role::Moderator | Role::Admin),
        Route::Billing => matches!(role, Role::Member | Role::Admin) && matches!(action, Action::View),
        Route::Support => !matches!(action, Action::Delete),
        Route::Api => match role {
            Role::Admin => true,
            Role::Moderator => !matches!(action, Action::Refund),
            _ => matches!(action, Action::View),
        },
    }
}

