struct Config {
    mode: Option<String>,
    endpoint: Option<String>,
    retries: Option<u32>,
    verbose: Option<bool>,
    timeout: Option<u32>,
    features: Option<Vec<String>>,
}

impl Config {
    fn merge(&mut self, other: &Config) {
        if let Some(v) = &other.mode {
            if !v.is_empty() {
                self.mode = Some(v.clone());
            }
        }
        if let Some(v) = &other.endpoint {
            if !v.is_empty() {
                self.endpoint = Some(v.clone());
            }
        }
        if let Some(v) = other.retries {
            if v > 0 {
                self.retries = Some(v);
            }
        }
        if let Some(v) = other.verbose {
            if v {
                self.verbose = Some(v);
            }
        }
        if let Some(v) = other.timeout {
            if v > 0 {
                self.timeout = Some(v);
            }
        }
        if let Some(v) = &other.features {
            if !v.is_empty() {
                self.features = Some(v.clone());
            }
        }
    }
}

impl fmt::Display for Config {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        let features = self.features.clone().unwrap_or_default().join(",");
        write!(
            f,
            "mode={}\nendpoint={}\nretries={}\nverbose={}\ntimeout={}\nfeatures=[{}]",
            self.mode.clone().unwrap_or_default(),
            self.endpoint.clone().unwrap_or_default(),
            self.retries.unwrap_or(0),
            self.verbose.unwrap_or(false),
            self.timeout.unwrap_or(0),
            features
        )
    }
}

