#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Entry {
    pub name: String,
    pub score: u32,
    pub solved: u32,
    pub penalty: u32,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct RankedEntry {
    pub rank: usize,
    pub name: String,
    pub score: u32,
    pub solved: u32,
    pub penalty: u32,
}

pub fn rank_entries(entries: &[Entry]) -> Vec<RankedEntry> {
    let mut merged: HashMap<String, Entry> = HashMap::new();
    for e in entries {
        let key = e.name.clone();
        merged
            .entry(key)
            .and_modify(|cur| {
                if e.score > cur.score {
                    *cur = e.clone();
                }
            })
            .or_insert_with(|| e.clone());
    }

    let mut rows: Vec<Entry> = merged.into_values().collect();
    rows.sort_by(|a, b| {
        b.score
            .cmp(&a.score)
            .then_with(|| b.solved.cmp(&a.solved))
            .then_with(|| a.penalty.cmp(&b.penalty))
    });

    let mut out = Vec::with_capacity(rows.len());
    for (i, e) in rows.into_iter().enumerate() {
        out.push(RankedEntry {
            rank: i + 1,
            name: e.name,
            score: e.score,
            solved: e.solved,
            penalty: e.penalty,
        });
    }
    out
}

