[dependencies]
",
    "src/lib.rs": "use std::collections::HashMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Record {
    pub id: u32,
    pub name: String,
    pub tags: Vec<String>,
    pub score: u8,
}

pub fn parse_records(input: &str) -> Result<Vec<Record>, String> {
    let mut out = Vec::new();
    for (line_no, raw) in input.lines().enumerate() {
        let line = raw.trim();
        if line.is_empty() {
            continue;
        }

        let mut fields: HashMap<&str, &str> = HashMap::new();
        for part in line.split(';') {
            let part = part.trim();
            if part.is_empty() {
                continue;
            }
            let (key, value) = part
                .split_once('=')
                .ok_or_else(|| format!("line {} malformed field", line_no + 1))?;
            fields.insert(key.trim(), value.trim());
        }

        let id = fields
            .get("id")
            .ok_or_else(|| format!("line {} missing id", line_no + 1))?
            .parse::<u32>()
            .map_err(|_| format!("line {} bad id", line_no + 1))?;

        let name = fields.get("name").copied().unwrap_or("").to_string();

        let tags = fields
            .get("tags")
            .map(|s| {
                s.split(',')
                    .filter(|t| !t.is_empty())
                    .map(|t| t.to_string())
