pub struct SaleRecord {
    pub week: u32,
    pub category: &'static str,
    pub customer_id: &'static str,
    pub amount_cents: i64,
    pub refunded: bool,
    pub region: &'static str,
}

pub fn weekly_category_report(records: &[SaleRecord], week: u32) -> String {
    let mut groups: BTreeMap<&str, (i64, usize, usize)> = BTreeMap::new();

    for r in records {
        if r.week != week {
            continue;
        }

        let entry = groups.entry(r.category).or_insert((0, 0, 0));
        entry.0 += r.amount_cents;
        entry.1 += 1;
        entry.2 += 1;
    }

    let mut rows: Vec<_> = groups.into_iter().collect();
    rows.sort_by(|a, b| a.0.cmp(b.0));

    let mut out = format!("week={}\n", week);
    for (category, (total, orders, customers)) in rows {
        out.push_str(&format!(
            "{} total={} orders={} customers={}\n",
            category, total, orders, customers
        ));
    }
    out
}

