fn merge(defaults: &Config, env: &PartialConfig, file: &PartialConfig, cli: &PartialConfig) -> Config {
    let endpoint = cli
        .endpoint
        .clone()
        .or_else(|| file.endpoint.clone())
        .or_else(|| env.endpoint.clone())
        .filter(|s| !s.is_empty())
